import time
from collections import deque
from sentence_transformers import SentenceTransformer
import numpy as np

class EmbeddingBatcher:
    def __init__(self, model, max_batch=64):
        self.model = model
        self.max_batch = max_batch
        self.queue = deque()
        self.total_encoded = 0
        self.total_latency_ms = 0

    def add(self, text: str):
        self.queue.append(text)

    def flush(self):
        batch = [self.queue.popleft()
                 for _ in range(min(len(self.queue), self.max_batch))]
        if not batch:
            return {"vectors": np.array([]), "count": 0}
        start = time.perf_counter()
        vectors = self.model.encode(batch, normalize_embeddings=True)
        ms = (time.perf_counter() - start) * 1000
        self.total_encoded += len(batch)
        self.total_latency_ms += ms
        return {"vectors": vectors, "count": len(batch), "latency_ms": ms}

    def avg_latency(self):
        if self.total_encoded == 0:
            return 0.0
        return self.total_latency_ms / self.total_encoded

model = SentenceTransformer("BAAI/bge-small-en-v1.5")
batcher = EmbeddingBatcher(model, max_batch=32)
for i in range(96):
    batcher.add(f"request {i}")
while batcher.queue:
    r = batcher.flush()
    print(f"Flushed {r['count']} docs")
print(f"Avg latency: {batcher.avg_latency():.2f}ms/doc")

